const countriesRes = $items('Get Dataset Countries', 0, 0)[0]?.json || {};
const remotiveRes = $items('Fetch Remotive Jobs', 0, 0)[0]?.json || {};
const arbeitRes = $items('Fetch Arbeitnow Jobs', 0, 0)[0]?.json || {};

const aliases = {
  'UK': 'United Kingdom',
  'USA': 'United States',
  'US': 'United States',
  'UAE': 'United Arab Emirates',
  'HongKong': 'Hong Kong'
};

const canonical = (c) => aliases[c] || c;
const countryList = Array.isArray(countriesRes.countries) && countriesRes.countries.length
  ? countriesRes.countries.map(canonical)
  : ['United Kingdom', 'United States', 'Canada', 'Australia', 'Germany', 'France', 'Netherlands', 'Ireland', 'Spain', 'Italy', 'Singapore', 'Switzerland'];

const countryTokens = {};
for (const c of countryList) {
  countryTokens[c] = [c.toLowerCase()];
}
countryTokens['United States'] = [...(countryTokens['United States'] || []), 'usa', 'us', 'united states'];
countryTokens['United Kingdom'] = [...(countryTokens['United Kingdom'] || []), 'uk', 'united kingdom', 'england'];
countryTokens['Hong Kong'] = [...(countryTokens['Hong Kong'] || []), 'hong kong', 'hongkong'];

const inferCountry = (location) => {
  const loc = String(location || '').toLowerCase();
  for (const [country, tokens] of Object.entries(countryTokens)) {
    if (tokens.some((t) => loc.includes(t))) return country;
  }
  return null;
};

const entryPattern = /(graduate|intern|internship|junior|entry|student|trainee)/i;
const jobs = [];

for (const j of Array.isArray(remotiveRes.jobs) ? remotiveRes.jobs : []) {
  const title = j.title || '';
  const category = j.category || '';
  const location = j.candidate_required_location || 'Remote';
  const isEntry = entryPattern.test(`${title} ${category}`);
  const country = inferCountry(location);
  if (!isEntry) continue;
  if (countryList.length && country && !countryList.includes(country)) continue;

  jobs.push({
    title: title || 'Role',
    company: j.company_name || 'Unknown',
    salary: j.salary || 'Competitive',
    location: country ? `${location} (${country})` : location,
    job_type: /intern/i.test(title) ? 'internship' : 'graduate',
    apply_link: j.url || '#',
    source: 'remotive'
  });
}

for (const j of Array.isArray(arbeitRes.data) ? arbeitRes.data : []) {
  const title = j.title || '';
  const tags = Array.isArray(j.tags) ? j.tags.join(' ') : '';
  const location = j.location || 'Remote';
  const country = inferCountry(location);
  const isEntry = entryPattern.test(`${title} ${tags}`);
  if (!isEntry) continue;
  if (countryList.length && country && !countryList.includes(country)) continue;

  jobs.push({
    title: title || 'Role',
    company: j.company_name || 'Unknown',
    salary: 'Competitive',
    location: country ? `${location} (${country})` : location,
    job_type: /intern/i.test(title) ? 'internship' : 'graduate',
    apply_link: j.url || '#',
    source: 'arbeitnow'
  });
}

const dedup = new Map();
for (const job of jobs) {
  const key = `${job.apply_link}::${job.title.toLowerCase()}::${job.company.toLowerCase()}`;
  if (!dedup.has(key)) dedup.set(key, job);
}

const finalJobs = Array.from(dedup.values()).slice(0, 800);
return [{ json: { jobs: finalJobs } }];
